#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int a;
        int freq[1001]={0};
        bool seen[1001]={false};
        bool ok=true;
        int prev=-1;
        for(int i=0;i<N;i++){
            scanf("%d",&a);
            if(prev!=-1 && a!=prev && seen[a]) ok=false; // non‑contiguous
            seen[a]=true;
            freq[a]++;
            prev=a;
        }
        if(ok){
            bool freqSeen[1001]={false};
            for(int v=1;v<=1000;v++) if(freq[v]>0){
                if(freqSeen[freq[v]]){ ok=false; break; }
                freqSeen[freq[v]]=true;
            }
        }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

